const data = $('Extract Event Data').first().json;
const ended = $('Log Call Ended').first().json;

// Build transcript string from Retell format
let transcript = ended.transcript || data.transcript || '';
// Retell sends transcript as object/array sometimes — convert to string
if (typeof transcript === 'object') {
  try { transcript = JSON.stringify(transcript); } catch(e) { transcript = String(transcript); }
}

return [{ json: {
  'Email': data.email || '',
  'Call ID': ended.call_id || data.call_id || '',
  'Call Status': 'ended',
  'Transcript': transcript,
  'Duration (sec)': (ended.duration_ms || data.duration_ms) ? Math.round((ended.duration_ms || data.duration_ms) / 1000) : ''
} }];

